<!DOCTYPE html>
<html lang="id">
<head>
    <meta charset="utf-8">
    <meta name="viewport" content="width=device-width, initial-scale=1">
    <title>Display Antrean - {{ $clinic?->name ?? 'Klinik' }}</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700&family=Manrope:wght@600;700;800&display=swap" rel="stylesheet">
    <style>
        :root{color-scheme:dark;--ink:#07111f;--panel:rgba(14,30,49,.82);--line:rgba(255,255,255,.1);--cyan:#55e6d3;--blue:#6eb8ff;--muted:#9db0c5}*{box-sizing:border-box}body{margin:0;min-height:100vh;overflow:hidden;background:radial-gradient(circle at 12% 18%,rgba(34,211,238,.16),transparent 30%),radial-gradient(circle at 90% 85%,rgba(59,130,246,.18),transparent 34%),linear-gradient(145deg,#06101e,#0a1728 56%,#07111f);color:#f8fbff;font-family:'DM Sans',sans-serif}.shell{height:100vh;padding:clamp(14px,1.55vw,28px);display:grid;grid-template-rows:auto minmax(0,1fr) auto auto;gap:clamp(11px,1.1vw,19px)}header{display:flex;align-items:center;justify-content:space-between}.brand{display:flex;align-items:center;gap:14px}.logo{width:48px;height:48px;border-radius:16px;display:grid;place-items:center;background:linear-gradient(145deg,var(--cyan),#3ba7fa);color:#06101e;font:800 24px Manrope;box-shadow:0 12px 34px rgba(85,230,211,.2)}.eyebrow{font-size:11px;letter-spacing:.18em;text-transform:uppercase;color:var(--cyan);font-weight:700}.clinic{margin-top:3px;font:700 clamp(19px,1.7vw,27px) Manrope}.clock{text-align:right}.clock strong{display:block;font:800 clamp(23px,2.3vw,36px) Manrope}.clock span{font-size:12px;color:var(--muted)}main{min-height:0;display:grid;grid-template-columns:minmax(0,1.65fr) minmax(280px,.8fr);gap:clamp(12px,1.2vw,20px)}.hero,.recent,.poli-board{border:1px solid var(--line);background:var(--panel);backdrop-filter:blur(20px);box-shadow:0 22px 64px rgba(0,0,0,.22)}.hero{position:relative;overflow:hidden;border-radius:27px;padding:clamp(22px,2.5vw,42px);display:flex;flex-direction:column;justify-content:center}.hero:after{content:'';position:absolute;width:330px;height:330px;border-radius:50%;right:-130px;top:-170px;background:radial-gradient(circle,rgba(85,230,211,.17),transparent 65%)}.label{font-size:clamp(12px,1vw,16px);letter-spacing:.16em;text-transform:uppercase;color:var(--cyan);font-weight:700}.number{margin:clamp(5px,.7vw,11px) 0;font:800 clamp(66px,8.5vw,138px)/.92 Manrope;letter-spacing:-.065em;text-shadow:0 8px 50px rgba(110,184,255,.16)}.patient{font:700 clamp(20px,2.4vw,38px)/1.1 Manrope;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.destination{margin-top:clamp(14px,1.4vw,24px);display:flex;gap:9px;flex-wrap:wrap}.pill{border:1px solid var(--line);background:rgba(255,255,255,.055);padding:8px 13px;border-radius:999px;color:#dce8f5;font-size:clamp(11px,.9vw,14px)}.pill b{color:white}.pulse{animation:pulse .7s ease 2}@keyframes pulse{50%{transform:scale(1.012);box-shadow:0 0 0 8px rgba(85,230,211,.08),0 26px 80px rgba(0,0,0,.25)}}.recent{border-radius:24px;padding:19px;display:flex;min-height:0;flex-direction:column}.recent h2{font:700 16px Manrope;margin:0 0 13px}.list{display:grid;gap:8px;overflow:hidden}.item{display:grid;grid-template-columns:minmax(82px,auto) minmax(0,1fr) auto;align-items:center;gap:10px;padding:10px 11px;border-radius:15px;background:rgba(255,255,255,.045);border:1px solid rgba(255,255,255,.065)}.item-number{font:800 17px Manrope;color:var(--blue);white-space:nowrap}.item-name{font-size:12px;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.item-poli,.item-time{font-size:10px;color:var(--muted)}.poli-board{border-radius:22px;padding:13px 15px}.poli-head{display:flex;align-items:center;justify-content:space-between;margin-bottom:10px}.poli-head h2{margin:0;font:700 14px Manrope}.poli-head span{font-size:10px;color:var(--muted);letter-spacing:.08em;text-transform:uppercase}.poli-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(185px,1fr));gap:9px}.poli-card{display:grid;grid-template-columns:38px 1fr auto;gap:10px;align-items:center;min-height:67px;padding:10px 12px;border:1px solid rgba(255,255,255,.075);border-radius:16px;background:rgba(255,255,255,.04)}.poli-icon{width:38px;height:38px;border-radius:13px;display:grid;place-items:center;background:linear-gradient(145deg,rgba(85,230,211,.19),rgba(110,184,255,.17));color:var(--cyan);font:800 13px Manrope}.poli-name{font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.05em}.poli-number{margin-top:2px;font:800 22px Manrope;color:#fff}.poli-time{align-self:end;font-size:10px;color:var(--muted)}footer{display:flex;justify-content:space-between;align-items:center;color:var(--muted);font-size:11px}.status{display:flex;align-items:center;gap:8px}.dot{width:8px;height:8px;border-radius:50%;background:var(--cyan);box-shadow:0 0 14px var(--cyan)}button{border:1px solid rgba(85,230,211,.35);background:rgba(85,230,211,.1);color:#dffff9;border-radius:999px;padding:8px 14px;font:600 11px 'DM Sans';cursor:pointer}button.active{border-color:var(--line);background:rgba(255,255,255,.05);color:var(--muted)}.empty{color:var(--muted);font-size:14px}.hidden{display:none}@media(max-width:820px){body{overflow:auto}.shell{height:auto;min-height:100vh}main{grid-template-columns:1fr}.hero{min-height:48vh}.recent{min-height:280px}.number{font-size:24vw}.clock span{display:none}.poli-grid{grid-template-columns:1fr 1fr}}@media(max-width:520px){.poli-grid{grid-template-columns:1fr}}
    </style>
</head>
<body>
<div class="shell">
    <header><div class="brand"><div class="logo">+</div><div><div class="eyebrow">Layanan Antrean Digital</div><div class="clinic">{{ $clinic?->name ?? 'Klinik belum diaktifkan' }}</div></div></div><div class="clock"><strong id="clock">--:--</strong><span id="date">Memuat tanggal...</span></div></header>
    <main>
        <section id="hero" class="hero"><div class="label">Panggilan Saat Ini</div><div id="empty" class="empty">Menunggu panggilan antrean...</div><div id="call" class="hidden"><div id="number" class="number">-</div><div id="patient" class="patient">-</div><div class="destination"><div class="pill">Tujuan: <b id="clinic-name">-</b></div><div class="pill">Dokter: <b id="doctor">-</b></div></div></div></section>
        <aside class="recent"><h2>Panggilan Sebelumnya</h2><div id="recent" class="list"><div class="empty">Belum ada riwayat hari ini.</div></div></aside>
    </main>
    <section class="poli-board"><div class="poli-head"><h2>Informasi Antrean Per Poli</h2><span>Berdasarkan jadwal hari ini</span></div><div id="polis" class="poli-grid"><div class="empty">Memuat jadwal poli...</div></div></section>
    <footer><div class="status"><span class="dot"></span><span id="connection">Display terhubung</span></div><button id="sound">Aktifkan suara panggilan</button></footer>
</div>
<script src="https://code.responsivevoice.org/responsivevoice.js?key=jgnnOkio"></script>
<script>
const initial=@json($initialState);let latestId=initial.latest?.id??null;let soundEnabled=localStorage.getItem('queue-display-sound')==='on';
const el=id=>document.getElementById(id), soundButton=el('sound');
function updateClock(){const now=new Date();el('clock').textContent=now.toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'}).replace('.',':');el('date').textContent=now.toLocaleDateString('id-ID',{weekday:'long',day:'2-digit',month:'long',year:'numeric'});}updateClock();setInterval(updateClock,1000);
function setSoundState(){soundButton.textContent=soundEnabled?'Suara panggilan aktif':'Aktifkan suara panggilan';soundButton.classList.toggle('active',soundEnabled)}setSoundState();
soundButton.addEventListener('click',()=>{soundEnabled=!soundEnabled;localStorage.setItem('queue-display-sound',soundEnabled?'on':'off');setSoundState();if(soundEnabled&&initial.latest)speak(initial.latest)});
function speechCase(value){return String(value||'').split(/(\s+|-)/).map(part=>/^[A-ZÀ-ÖØ-Þ]{2,}$/.test(part)?part.charAt(0)+part.slice(1).toLocaleLowerCase('id-ID'):part).join('')}
function speak(call){if(!soundEnabled)return;const queue=String(call.nomor).replace(/[-_/]/g,' ');const patient=speechCase(call.nama);const clinic=speechCase(call.spesialis||'poli tujuan');const doctor=speechCase(String(call.dokter||'').replace(/^\s*(?:dr\.?|dokter)\s*/i,'').trim());const text=`Nomor antrean ${queue}, atas nama ${patient}. Silakan menuju ${clinic}${doctor?', dengan dokter '+doctor:''}.`;
if(window.responsiveVoice){window.responsiveVoice.cancel();window.responsiveVoice.speak(text,'Indonesian Female',{rate:.86,pitch:1,volume:1});return}
if(!('speechSynthesis'in window))return;window.speechSynthesis.cancel();const speech=new SpeechSynthesisUtterance(text);speech.lang='id-ID';speech.rate=.82;speech.pitch=1;const voices=speechSynthesis.getVoices();const voice=voices.find(v=>v.lang.toLowerCase()==='id-id')||voices.find(v=>v.lang.toLowerCase().startsWith('id'))||voices.find(v=>/indonesia|andika|gadis/i.test(v.name));if(voice)speech.voice=voice;window.speechSynthesis.speak(speech)}
function render(state,announce=false){const call=state.latest;if(call){el('empty').classList.add('hidden');el('call').classList.remove('hidden');el('number').textContent=call.nomor;el('patient').textContent=call.nama;el('clinic-name').textContent=call.spesialis||'-';el('doctor').textContent=call.dokter||'-';if(announce){el('hero').classList.remove('pulse');void el('hero').offsetWidth;el('hero').classList.add('pulse');speak(call)}}const items=state.recent||[];el('recent').innerHTML=items.length?items.map(item=>`<div class="item"><div class="item-number">${escapeHtml(item.nomor)}</div><div><div class="item-name">${escapeHtml(item.nama)}</div><div class="item-poli">${escapeHtml(item.spesialis||'-')}</div></div><div class="item-time">${escapeHtml(item.waktu||'')}</div></div>`).join(''):'<div class="empty">Belum ada riwayat hari ini.</div>';const polis=state.polis||[];el('polis').innerHTML=polis.length?polis.map((poli,index)=>`<div class="poli-card"><div class="poli-icon">${String(index+1).padStart(2,'0')}</div><div><div class="poli-name">${escapeHtml(poli.nama)}</div><div class="poli-number">${escapeHtml(poli.nomor||'---')}</div></div><div class="poli-time">${escapeHtml(poli.waktu||'Menunggu')}</div></div>`).join(''):'<div class="empty">Tidak ada jadwal poli hari ini.</div>'}
function escapeHtml(value){const div=document.createElement('div');div.textContent=value??'';return div.innerHTML}
async function refresh(){try{const response=await fetch('{{ route('api.display.state') }}',{headers:{Accept:'application/json'},cache:'no-store'});if(!response.ok)throw new Error();const state=await response.json();const next=state.latest?.id??null;render(state,next!==null&&next!==latestId);latestId=next;el('connection').textContent='Display terhubung'}catch(e){el('connection').textContent='Mencoba menghubungkan kembali...'}}render(initial);setInterval(refresh,1000);
</script>
</body>
</html>
